import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as n,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/auto-tagging.md","filePath":"ms-MY/Other/auto-tagging.md","lastUpdated":1781962217000}'),l={name:"ms-MY/Other/auto-tagging.md"};function d(g,a,o,p,r,u){return n(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging dikonfigurasi di bawah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Ia menjana image tags secara automatik. Tags ini berguna untuk search, random image filtering, public gallery filtering dan age-rating access control.</p><h2 id="fungsi-auto-tagging" tabindex="-1">Fungsi Auto Tagging <a class="header-anchor" href="#fungsi-auto-tagging" aria-label="Permalink to &quot;Fungsi Auto Tagging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Generate content tags</td><td>Menambah tags untuk people, scenes, objects, art style dan visual content yang seumpamanya.</td></tr><tr><td>Generate character tags</td><td>Berguna untuk anime images dan illustrations.</td></tr><tr><td>Add orientation tags</td><td>Menambah <code>landscape</code>, <code>portrait</code> atau <code>square</code>.</td></tr><tr><td>Add image rating</td><td>Menyimpan rating results <code>G/S/Q/E</code> untuk general, sensitive, questionable atau explicit content.</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images masuk ke tagging flow secara automatik.</td></tr><tr><td>Batch tagging</td><td>Menambah tags kepada old images dalam semua folders atau selected folders.</td></tr></tbody></table><h2 id="perkara-yang-diperlukan-dahulu" tabindex="-1">Perkara Yang Diperlukan Dahulu <a class="header-anchor" href="#perkara-yang-diperlukan-dahulu" aria-label="Permalink to &quot;Perkara Yang Diperlukan Dahulu&quot;">​</a></h2><p>Sediakan sekurang-kurangnya satu Hugging Face Space URL yang boleh diakses.</p><p>Cara recommended ialah duplicate Space <code>wd-tagger</code> milik SmilingWolf ke Hugging Face account anda sendiri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Anda boleh menggunakan public Space sementara, tetapi public Spaces dikongsi oleh ramai users dan mungkin queue, perlahan atau unavailable. Space yang diduplicate di bawah account anda sendiri lebih stabil untuk auto tagging jangka panjang.</p><h2 id="duplicate-space-smilingwolf" tabindex="-1">Duplicate Space SmilingWolf <a class="header-anchor" href="#duplicate-space-smilingwolf" aria-label="Permalink to &quot;Duplicate Space SmilingWolf&quot;">​</a></h2><ol><li>Sign in ke Hugging Face.</li><li>Buka <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+e+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Klik menu tiga titik di penjuru kanan atas.</li><li>Pilih <code>Duplicate this Space</code>.</li><li>Kekalkan Space name default atau pilih nama sendiri, contohnya <code>wd-tagger</code>.</li><li>Tetapkan visibility kepada <code>Public</code>. Public Spaces lebih mudah dipanggil oleh ImgBed.</li><li>Mulakan dengan default free hardware dahulu. Upgrade kemudian hanya jika queueing jelas berlaku.</li><li>Cipta Space dan tunggu build selesai.</li></ol><p>Selepas build selesai, buka Space page anda. URL biasanya kelihatan seperti:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Copy browser URL dan paste ke <code>Space URLs</code> dalam ImgBed.</p><h2 id="mengisi-multiple-space-urls" tabindex="-1">Mengisi Multiple Space URLs <a class="header-anchor" href="#mengisi-multiple-space-urls" aria-label="Permalink to &quot;Mengisi Multiple Space URLs&quot;">​</a></h2><p>Masukkan satu Space URL setiap baris.</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. Baik untuk temporary testing.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Copied Space page URL.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Space yang anda duplicate sendiri.</td></tr></tbody></table><p>Anda boleh masukkan beberapa URLs. ImgBed menggunakan beberapa Spaces bersama-sama, yang boleh meningkatkan speed.</p><p>Jika satu Space temporarily unavailable, Space lain masih boleh terus processing.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Masukkan Space URLs yang disediakan. Gunakan sekurang-kurangnya satu.</td></tr><tr><td>Target folder</td><td>Biarkan kosong untuk semua folders. Pilih folder hanya jika mahu process directory tertentu.</td></tr><tr><td>Recognition model</td><td>Kekalkan <code>wd-swinv2-tagger-v3</code> secara default.</td></tr><tr><td>General tag threshold</td><td>Default sesuai untuk kebanyakan images. Nilai lebih rendah menghasilkan lebih banyak tags; nilai lebih tinggi menghasilkan kurang tags.</td></tr><tr><td>Character tag threshold</td><td>Default lebih conservative dan membantu mengelakkan character tags yang salah.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Biarkan off pada permulaan. Hidupkan apabila mahu model menentukan jumlah tags secara automatik.</td></tr><tr><td>Auto-tag on upload</td><td>Hidupkan jika newly uploaded images patut mendapat tags secara automatik.</td></tr><tr><td>Start tagging</td><td>Batch-tag old images secara manual.</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Off pada permulaan</td></tr><tr><td>Auto-tag on upload</td><td>Enable jika perlu</td></tr></tbody></table><p>Jika tags terlalu banyak, naikkan general threshold sedikit.</p><p>Jika tags terlalu sedikit, turunkan general threshold sedikit.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Isi <code>Space URLs</code>.</li><li>Pilih target folder.</li><li>Klik start tagging.</li><li>Tunggu progress selesai.</li></ol><p>Jika target folder kosong, ImgBed process semua folders.</p><p>Batch tagging paling sesuai untuk old images. Untuk new images, enable auto-tag on upload supaya tidak perlu run secara manual setiap kali.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Selepas auto-tag on upload diaktifkan, newly uploaded images memanggil <code>Space URLs</code> yang dikonfigurasi secara automatik.</p><p>Ini sesuai untuk penggunaan jangka panjang.</p><p>Jika Space sedang queueing, upload masih boleh selesai dahulu dan tagging diteruskan selepas itu.</p><h2 id="images-yang-diproses" tabindex="-1">Images Yang Diproses <a class="header-anchor" href="#images-yang-diproses" aria-label="Permalink to &quot;Images Yang Diproses&quot;">​</a></h2><p>Auto tagging terutama memproses image files.</p><p>Images yang sudah mempunyai tags, orientation, rating, width dan height lengkap akan diskip untuk mengelakkan Space calls yang tidak perlu.</p><p>ImgBed hanya mengisi maklumat yang hilang apabila boleh. Contohnya, jika hanya orientation hilang, ia cuba menambah orientation tanpa memanggil full content tag flow.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="mengapa-perlu-duplicate-space-sendiri" tabindex="-1">Mengapa Perlu Duplicate Space Sendiri? <a class="header-anchor" href="#mengapa-perlu-duplicate-space-sendiri" aria-label="Permalink to &quot;Mengapa Perlu Duplicate Space Sendiri?&quot;">​</a></h3><p>Public Spaces dikongsi oleh ramai users. Space duplicate anda digunakan terutamanya oleh ImgBed site anda, jadi biasanya lebih laju dan reliable.</p><h3 id="space-asyik-starting-up" tabindex="-1">Space Asyik Starting Up <a class="header-anchor" href="#space-asyik-starting-up" aria-label="Permalink to &quot;Space Asyik Starting Up&quot;">​</a></h3><p>Selepas creation pertama, atau selepas idle lama, Space mungkin memerlukan masa untuk start.</p><p>Buka Space page anda dahulu. Selepas ia boleh recognize image secara normal, kembali ke ImgBed dan start tagging.</p><h3 id="bagaimana-copy-space-url" tabindex="-1">Bagaimana Copy Space URL? <a class="header-anchor" href="#bagaimana-copy-space-url" aria-label="Permalink to &quot;Bagaimana Copy Space URL?&quot;">​</a></h3><p>Buka Hugging Face Space page anda dan copy browser address.</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="bolehkah-tambah-multiple-spaces" tabindex="-1">Bolehkah Tambah Multiple Spaces? <a class="header-anchor" href="#bolehkah-tambah-multiple-spaces" aria-label="Permalink to &quot;Bolehkah Tambah Multiple Spaces?&quot;">​</a></h3><p>Boleh. Masukkan satu Space URL setiap baris.</p><p>Multiple Spaces process images bersama-sama dan berguna apabila anda mempunyai banyak images.</p><h3 id="mengapa-tags-dalam-english" tabindex="-1">Mengapa Tags Dalam English? <a class="header-anchor" href="#mengapa-tags-dalam-english" aria-label="Permalink to &quot;Mengapa Tags Dalam English?&quot;">​</a></h3><p>SmilingWolf models output English tags. Ini normal.</p><p>Tags digunakan terutamanya untuk search, filtering, random image API dan public gallery filters.</p><h3 id="rating-tags-digunakan-untuk-apa" tabindex="-1">Rating Tags Digunakan Untuk Apa? <a class="header-anchor" href="#rating-tags-digunakan-untuk-apa" aria-label="Permalink to &quot;Rating Tags Digunakan Untuk Apa?&quot;">​</a></h3><p>Rating results berfungsi bersama access mode dalam Security Settings.</p><p>Contohnya, apabila visitor access dihadkan oleh age rating, public browsing dan random image features akan filter images mengikut rules tersebut.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in ke Hugging Face</span></span>
<span class="line"><span>-&gt; Buka SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Tunggu Space selesai build</span></span>
<span class="line"><span>-&gt; Copy Space URL anda</span></span>
<span class="line"><span>-&gt; Isi Space URLs dalam ImgBed</span></span>
<span class="line"><span>-&gt; Pilih model dan thresholds</span></span>
<span class="line"><span>-&gt; Start tagging atau enable auto-tag on upload</span></span></code></pre></div>`,63)])])}const k=t(l,[["render",d]]);export{m as __pageData,k as default};
